#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if(!(cin>>n)) return 0;
    vector<int> arr(n);
    for(int i=0;i<n;++i) cin>>arr[i];
    int k; cin>>k;
    unordered_map<int,long long> freq;
    freq.reserve(n*2);
    freq.max_load_factor(0.7);
    freq[0]=1;
    int px=0;
    long long count=0;
    for(int v:arr){
        px ^= v;
        int need = px ^ k;
        auto it = freq.find(need);
        if(it!=freq.end()) count += it->second;
        ++freq[px];
    }
    cout<<count;
    return 0;
}
